// Script Continued Below
// STRY0067125 - added to align with rules on Task
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading) {
		return;
	}
	// STRY0114396
	//if(newValue === ''){
	//	g_form.setDisplay('assigned_to_individual',false);
	//	g_form.setDisabled('assigned_to_individual', true);
	//	return;
	//}
	// Clears assigned members from old office.
	//g_form.clearValue("assigned_to_individual");

	//Type appropriate comment here, and begin script below
	// Determine duration.
	//  RAJ STSK0011104 - allow changing task assingment based on user being a tasking authority 
	//  changed the script include to add a method to determine if the user is a Tasking Authority
	var UserPermissions  = new GlideAjax('ClientUserInfoScripts');
	UserPermissions.addParam('sysparm_name','CanUserAssignSelfOrOthersInTemplate');
	UserPermissions.addParam("OU", newValue);
	UserPermissions.addParam("UserId", g_user.userID);
	UserPermissions.addParam("Template", g_form.getValue('tasker_process_definition'));

	// call script include to determine if this user is a tasking authority of the primary assignee OU.
	UserPermissions.getXML(f_returnCanUserAssignSelfOrOthersInTemplate);

}


function f_returnCanUserAssignSelfOrOthersInTemplate(response)
{

	var answer = response.responseXML.documentElement.getAttribute("answer");
	// if the current user is a Tasking Authority in the OU, allow them to change the assigned members
	// STRY0114396 - stop hiding the field
	//g_form.setDisplay('assigned_to_individual',answer);
	g_form.setDisabled('assigned_to_individual', !answer);

}
